Code.Terraform:
```hcl
resource "aws_secretsmanager_secret_policy" "<example_resource_name>" {
  secret_arn = "<example_resource_id>"
  policy = jsonencode({  # Critical: deny-by-default with explicit exceptions
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Deny"
        Principal = "*"
        Action    = "*"
        Resource  = "*"
        Condition = {
          StringNotEquals = {
            "aws:PrincipalArn" = ["<AUTHORIZED_ROLE_ARN>"]
          }
        }
      }
    ]
  })
}
```
